def bullets(values):
    return '\n'.join(f'- {value}' for value in values)

def build_context(brief):
    slug, title, client, buyer, request, pains, scope, outcome, positioning = brief
    return (
        f'# Коммерческий контекст: {title}\n\n'
        f'{NOTICE}\n\n'
        '## Кто обычно заказывает\n\n'
        f'- Тип бизнеса: {client}\n'
        f'- Кто принимает решение: {buyer}\n\n'
        '## Как звучит типовой запрос\n\n'
        f'> {request}\n\n'
        '## Что болит у заказчика\n\n'
        f'{bullets(pains)}\n\n'
        '## Что я беру на себя как разработчик\n\n'
        f'{bullets(scope)}\n\n'
        '## Какой результат получает бизнес\n\n'
        f'{bullets(outcome)}\n\n'
        '## Как использовать этот кейс в профиле\n\n'
        f'{positioning}\n'
    )

def build_readme_block(brief):
    slug, title, client, buyer, request, pains, scope, outcome, positioning = brief
    return (
        f'{START}\n'
        '## Живой коммерческий контекст\n\n'
        f'- Типовой заказчик: {client}\n'
        f'- Кто принимает решение: {buyer}\n'
        f'- Типовой запрос: {request}\n'
        '- Формат подачи: это публичный showcase на основе реального рыночного сценария, а не выдуманная история про клиента.\n'
        '- [Полный коммерческий разбор](./COMMERCIAL_CONTEXT.md)\n'
        f'{END}'
    )

def replace_or_append(text, block):
    if START in text and END in text:
        start = text.index(START)
        end = text.index(END) + len(END)
        return text[:start].rstrip() + '\n\n' + block + '\n'
    return text.rstrip() + '\n\n' + block + '\n'

for brief in briefs:
    slug = brief[0]
    root = PROJECTS / slug
    (root / 'COMMERCIAL_CONTEXT.md').write_text(build_context(brief), encoding='utf-8')
    readme_path = root / 'README.md'
    readme_path.write_text(replace_or_append(readme_path.read_text(encoding='utf-8'), build_readme_block(brief)), encoding='utf-8')

